A. Red Versus Blue思路计算出最多可以分成几段，多余的 R 在每段中增加一个
#include&lt;bits/stdc++.h&gt;
void solve() &#123;
    int n,r,b;
    std::cin &gt;&gt; n &gt;&gt; r &gt;&gt; b;
    int x = r / (b + 1), y = r % (b + 1);
    int pos = 1;
    while(pos &lt;= n) &#123;
        int t = 1;
        while(pos &lt;= n &amp;&amp; t &lt;= x) &#123;
            std::cout &lt;&lt; &quot;R&quot;;
            pos++;
            t++;
        &#125;
        if(pos &gt; n) break;
        if(y) &#123;
            std::cout &lt;&lt; &quot;RB&quot;;
            pos +=2;
            y--;
        &#125;
        else &#123;
            std::cout &lt;&lt; &quot;B&quot;;
            pos ++;
        &#125;
    &#125;
    std::cout &lt;&lt; &#39;\n&#39;;
&#125;
int main() &#123;
&#125;
```## B. Bit Flipping

## 思路 (重复2)

将总次数分为奇数与偶数考虑

总次数为奇数时，每一个位置都会变号，如果选择一次，那么该位置不变号

总次数为偶数时，每个位置不变号，如果选择一次，那么该位置变号

从高位向低位依次判断

```c++
#include&lt;bits/stdc++.h&gt;
void solve() &#123;
    int n,k;
    std::cin &gt;&gt; n &gt;&gt; k;
    std::string s;
    std::cin &gt;&gt; s;
    int len = s.length();
    std::vector&lt;int&gt; f(n);
    int pos = k;
    for(int i = 0; i &lt; len; i++) &#123;
        if(k &amp; 1) &#123;
            if(s[i] == &#39;1&#39;) &#123;
                if(pos) &#123;
                    f[i] = 1;
                    pos--;
                &#125;
                else s[i] = &#39;0&#39;;
            &#125;
            else &#123;
                s[i] = &#39;1&#39;;
            &#125;
        &#125;
        else &#123;
            if(s[i] == &#39;0&#39;) &#123;
                if(pos) &#123;
                    f[i] = 1;
                    s[i] = &#39;1&#39;;
                    pos--;
                &#125;
            &#125;
        &#125;
    &#125;
    if(pos) &#123;
        f[len - 1] += pos;
        if(pos &amp; 1) &#123;
            if(s[len - 1] == &#39;1&#39;) s[len - 1] = &#39;0&#39;;
            else s[len - 1] = &#39;1&#39;;
        &#125;
    &#125;
    std::cout &lt;&lt; s &lt;&lt; &#39;\n&#39;;
    for(int x : f)
        std::cout &lt;&lt; x &lt;&lt; &#39; &#39;;
    std::cout &lt;&lt; &#39;\n&#39;;
&#125;
int main() &#123;
&#125;
```## C. Line Empire

## 思路 (重复3)

简单贪心，考虑相邻两个城堡之间路的代价

如果移动，那么代价为 $a\times c$

如果不移动，那么代价为 $b\times c\times (n-i)$ ，即后面有多少个城堡经过这条路

取较小值

```c++
#include&lt;bits/stdc++.h&gt;
void solve() &#123;
    int n,a,b;
    std::cin &gt;&gt; n &gt;&gt; a &gt;&gt; b;
    std::vector&lt;int&gt; x(n + 1);
    for(int i = 1; i &lt;= n; i++)
        std::cin &gt;&gt; x[i];
    long long sum = 0;
    for(int i = 1; i &lt;= n; i++)
        sum += x[i];
    long long ans = 0;
    int pos = 0;
    for(int i = 1; i &lt;= n; i++) &#123;
        ans += 1ll * b * (x[i] - pos);
        sum -= (x[i] - pos);
        if(i == n) break;
        if(sum * b &gt;=
            1ll * (sum - 1ll * (n - i) * (x[i] - pos)) * b
            + 1ll * a * (x[i] - pos)) &#123;
            ans += 1ll * a * (x[i] - pos);
            pos = x[i];
        &#125;
    &#125;
    std::cout &lt;&lt; ans &lt;&lt; &#39;\n&#39;;
&#125;
int main() &#123;
&#125;
```## D. Reverse Sort Sum

## 思路 (重复4)

&gt; 想了一个小时没想出来。。。
&gt;
&gt; 裂开

根据输入，可以计算出一共有多少个 $1$ ，即 $B_n$ 应该是什么样子的

从 $B_n$ 往前推，考虑 $B_i$ 中的最后一个 $1$ 有没有可能是一直存在的，即考虑前 $i$ 个回合，第 $i$ 个点的贡献是不是等于 $i$

我们已知第 $i$ 个点在 $n$ 个回合中的总贡献为 $c_i$ ，把 $i+1\sim n$ 轮中，第 $i$ 个点的贡献去掉即可

区间减法使用差分的方式优化时间

```c++
#include&lt;bits/stdc++.h&gt;
void solve() &#123;
    int n;
    std::cin &gt;&gt; n;
    std::vector&lt;int&gt; f(n + 1),g(n + 1);
    std::vector&lt;int&gt; ans(n + 1);
    long long sum = 0;
    for(int i = 1; i &lt;= n; i++)
        std::cin &gt;&gt; f[i];
    for(int i = 1; i &lt;= n; i++) sum += f[i];
    int k = sum / n,del = 0;
    for(int i = n; i &gt;= 1; i--) &#123;
        f[i] += del;
        del = del + g[i];
        if(k &gt; 1) &#123;
            del--;
            g[i - k + 1] ++;
        &#125;
        if(f[i] == i) &#123;
            ans[i] = 1;
            k--;
        &#125;
    &#125;
