感觉我想复杂了，而且还没过。。。

考虑 $dfs$ 序将树变成数组

然后最小代价是 $dfs$ 序相邻的两个点之间的距离之和 $-$ 深度最大的点

离线倒序处理

&gt; 找到原因了，根节点可能不是 $1$ ，懒得改了，摆烂

```c++
#include&lt;bits/stdc++.h&gt;
const int MAXN = 2e5;
int n,m,tim;
std::vector&lt;std::vector&lt;int&gt;&gt; To,Fa;
std::vector&lt;int&gt; Deep,dfn,id;
void init() &#123;
    To.resize(MAXN + 1);
    Fa.resize(MAXN + 1,std::vector&lt;int&gt; (21));
    Deep.resize(MAXN + 1);
    dfn.resize(MAXN + 1);
    id.resize(MAXN + 1);
&#125;
void dfs(int u) &#123;
    dfn[u] = ++tim;
    id[tim] = u;
    Deep[u] = Deep[Fa[u][0]] + 1;
    for(int v : To[u]) &#123;
        Fa[v][0] = u;
        dfs(v);
    &#125;
&#125;
int Lca(int x,int y) &#123;
    if(Deep[x] &lt; Deep[y]) std::swap(x,y);
    for(int i = 20; i &gt;= 0; i--)
        if(Deep[Fa[x][i]] &gt;= Deep[y])
            x = Fa[x][i];
    if(x == y) return x;
    for(int i = 20; i &gt;= 0; i--)
        if(Fa[x][i] != Fa[y][i]) &#123;
            x = Fa[x][i];
            y = Fa[y][i];
        &#125;
    return Fa[x][0];
&#125;
int dist(int x,int y) &#123;
    int lca = Lca(x,y);
    return Deep[x] + Deep[y] - 2 * Deep[lca];
&#125;
int main() &#123;
    std::cin &gt;&gt; n &gt;&gt; m;
    init();
    for(int i = 1; i &lt;= n; i++) &#123;
        int x;
        std::cin &gt;&gt; x;
        if(x == -1) continue;
        To[x].push_back(i);
    &#125;
    dfs(1);
    for(int k = 1; k &lt;= 20; k++)
        for(int i = 1; i &lt;= n; i++)
            Fa[i][k] = Fa[Fa[i][k - 1]][k - 1];
    std::vector&lt;int&gt; ans(MAXN + 1),add(MAXN + 1),cnt(MAXN + 1);
    for(int i = 1; i &lt;= m; i++) &#123;
        std::cin &gt;&gt; add[i];
        cnt[add[i]]++;
    &#125;
    std::vector&lt;int&gt; nxt(MAXN + 1),pre(MAXN + 1);
    std::priority_queue&lt;int&gt; A,B;
    A.push(1);
    int pos = 1;
    for(int i = 2; i &lt;= n; i++) &#123;
        if(cnt[id[i]]) &#123;
            A.push(Deep[id[i]]);
            nxt[pos] = id[i];
            pre[id[i]] = pos;
            pos = id[i];
        &#125;
    &#125;
    nxt[pos] = 1;pre[1] = pos;

    int ANS = 0;
    pos = 1;
    while(true) &#123;
        ANS += dist(pos,nxt[pos]);
        if(nxt[pos] == 1) break;
        pos = nxt[pos];
    &#125;

    for(int i = m; i &gt;= 1; i--) &#123;
        ans[i] = ANS - (A.top() - 1);
        cnt[add[i]]--;
        if(cnt[add[i]] == 0) &#123;
            int x = add[i];
            int l = pre[x];
            int r = nxt[x];
            ANS = ANS - dist(l,x) - dist(x,r) + dist(l,r);
            B.push(Deep[x]);
            nxt[l] = r;
            pre[r] = l;
        &#125;
        while(!B.empty() &amp;&amp; B.top() == A.top()) &#123;
            B.pop();
            A.pop();
        &#125;
    &#125;

    for(int i = 1; i &lt;= m; i++) &#123;
        std::cout &lt;&lt; ans[i] &lt;&lt; &#39;\n&#39;;
    &#125;
    return 0;
&#125;
