#include&lt;bits/stdc++.h&gt;int n,root = 1,ans;std::vector&lt;std::vector&lt;int&gt;&gt; To;std::vector&lt;int&gt; color;void dfs(int u,int fa) &#123;    std::vector&lt;bool&gt; book(ans + 1);    book[color[fa]] = true;    book[color[u]] = true;    int cnt = 1;    for(int v : To[u]) &#123;        if(v == fa) continue;        while(book[cnt]) cnt++;        color[v] = cnt;        dfs(v,u);        book[cnt] = true;    &#125;&#125;int main() &#123;    std::cin &gt;&gt; n;    To.resize(n + 1);    color.resize(n + 1);    for(int i = 1; i &lt; n; i++) &#123;        int x,y;        std::cin &gt;&gt; x &gt;&gt; y;        To[x].push_back(y);        To[y].push_back(x);    &#125;    for(int i = 1; i &lt;= n; i++)    &#123;        if(To[i].size() &gt; To[root].size())            root = i;    &#125;    ans = To[root].size() + 1;    color[root] = 1;    dfs(root, 0);    std::cout &lt;&lt; ans &lt;&lt; &#x27;\n&#x27;;    for(int i = 1; i &lt;= n; i++)        std::cout &lt;&lt; color[i] &lt;&lt; &#x27; &#x27;;&#125;

