合法的序列需要满足的条件有

深度单调不下降
当前的点对应的父亲节点应该是满足一定序列的

#include&lt;bits/stdc++.h&gt;int n;std::vector&lt;std::vector&lt;int&gt;&gt; To;std::vector&lt;int&gt; deep,Fa,a;void dfs(int u,int fa) &#123;    deep[u] = deep[fa] + 1;    for(int v : To[u]) &#123;        if(v == fa) continue;        Fa[v] = u;        dfs(v,u);    &#125;&#125;int main() &#123;    std::cin &gt;&gt; n;    To.resize(n + 1);    deep.resize(n + 1);    Fa.resize(n + 1);    a.resize(n + 1);    for(int i = 1; i &lt; n; i++) &#123;        int u,v;        std::cin &gt;&gt; u &gt;&gt; v;        To[u].push_back(v);        To[v].push_back(u);    &#125;    for(int i = 1; i &lt;= n; i++)        std::cin &gt;&gt; a[i];    dfs(1, 0);    bool flag = true;    int Dp = 0;    for(int i = 1; i &lt;= n; i++) &#123;        int u = a[i];        if(deep[u] &lt; Dp) flag = false;        if(deep[u] &gt; Dp) Dp = deep[u];    &#125;    if(flag) &#123;        std::queue&lt;int&gt; q[2];        int cnt = 0;        int now = 0,DP = 1;        for(int i = 1; i &lt;= n; i++) &#123;            int u = a[i], Deep = deep[u];            if(Deep == 1) &#123;                q[now].push(u);                continue;            &#125;            if(Deep != DP) &#123;                DP = Deep;                now ^= 1;            &#125;            if(To[u].size() != 1) q[now].push(u);            int ls = q[now ^ 1].front();            if(Fa[u] != ls)    &#123;                flag = false;                break;            &#125;            cnt++;            if(deep[ls] == 1 &amp;&amp; cnt == To[ls].size()) &#123;                q[now ^ 1].pop();                cnt = 0;            &#125;            if(deep[ls] != 1 &amp;&amp; cnt + 1 == To[ls].size()) &#123;                q[now ^ 1].pop();                cnt = 0;            &#125;        &#125;    &#125;    if(flag) std::cout &lt;&lt; &quot;Yes&quot;;    else std::cout &lt;&lt; &quot;No&quot;;    return 0;&#125;

