// 状压dp#include&lt;bits/stdc++.h&gt;int N,M,ans;std::string a[110];int s[110];int use[100],sum[100],cnt;int f[110][70][70];void DFS(int x,int step) &#123;    if(step &gt;= M) &#123;        use[++cnt] = x;        int S = 0;        for(int i = 0; i &lt; M; i++)            if(x &amp; (1 &lt;&lt; i)) S++;        sum[cnt] = S;        return;    &#125;    bool flag = true;    if(step &gt;= 1 &amp;&amp;        (x &amp; (1 &lt;&lt; (step - 1)) ) ) flag = false;    if(step &gt;= 2 &amp;&amp;        (x &amp; (1 &lt;&lt; (step - 2)) ) ) flag = false;    DFS(x,step + 1);    if(flag) DFS(x | (1 &lt;&lt; step),step + 1);&#125;int main() &#123;    std::cin &gt;&gt; N &gt;&gt; M;    for(int i = 1; i &lt;= N; i++) &#123;        std::cin &gt;&gt; a[i];        for(int j = 0; j &lt; M; j++)            if(a[i][j] == &#x27;H&#x27;) s[i] |= 1 &lt;&lt; j;    &#125;    DFS(0,0);    for(int i = 1; i &lt;= N; i++) &#123;        for(int j = 1; j &lt;= cnt; j++) &#123;            if(s[i] &amp; use[j]) continue;            for(int k = 1; k &lt;= cnt; k++) &#123;                if(use[j] &amp; use[k]) continue;                for(int p = 1; p &lt;= cnt; p++) &#123;                    if(use[j] &amp; use[p]) continue;                    f[i][j][k] = std::max(f[i][j][k],                        f[i - 1][k][p] + sum[j]);                &#125;            &#125;        &#125;    &#125;    int ans = 0;    for(int i = 1; i &lt;= cnt; i++)        for(int j = 1; j &lt;= cnt; j++)            ans = std::max(ans,f[N][i][j]);    std::cout &lt;&lt; ans &lt;&lt; &#x27;\n&#x27;;    return 0;&#125;

